import{_ as a,o as s,c as n,ag as o}from"./chunks/framework.ePeAWSvT.js";const u=JSON.parse('{"title":"ASR 模块","description":"","frontmatter":{},"headers":[],"relativePath":"guide/architecture/asr.md","filePath":"guide/architecture/asr.md"}'),l={name:"guide/architecture/asr.md"};function i(r,e,t,p,c,d){return s(),n("div",null,[...e[0]||(e[0]=[o(`<h1 id="asr-模块" tabindex="-1">ASR 模块 <a class="header-anchor" href="#asr-模块" aria-label="Permalink to &quot;ASR 模块&quot;">​</a></h1><p><code>src/lab/asr/</code> — 语音识别（FunASR / Whisper）。</p><h2 id="目录结构" tabindex="-1">目录结构 <a class="header-anchor" href="#目录结构" aria-label="Permalink to &quot;目录结构&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>asr/</span></span>
<span class="line"><span>├── asr_base_model.py    # ASRBaseModel 抽象基类</span></span>
<span class="line"><span>├── combiner.py          # 句子合并（短间隔句子拼接）</span></span>
<span class="line"><span>├── cutter.py            # 句子切分（长停顿处拆句）</span></span>
<span class="line"><span>├── funasr/</span></span>
<span class="line"><span>│   ├── method.py        # FunASR 推理（ASR + VAD + 标点恢复）</span></span>
<span class="line"><span>│   ├── extractor.py     # 结果解析与结构化</span></span>
<span class="line"><span>│   ├── converter.py     # ASR Response → Sentence 转换</span></span>
<span class="line"><span>│   └── model.py         # FunASR 模型定义</span></span>
<span class="line"><span>└── whisper/</span></span>
<span class="line"><span>    └── converter.py     # Whisper Response → Sentence 转换</span></span></code></pre></div><h2 id="核心概念" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念" aria-label="Permalink to &quot;核心概念&quot;">​</a></h2><h3 id="asrbasemodel" tabindex="-1">ASRBaseModel <a class="header-anchor" href="#asrbasemodel" aria-label="Permalink to &quot;ASRBaseModel&quot;">​</a></h3><p>抽象基类，定义三个接口：</p><ul><li><code>init_model()</code> — 加载模型权重</li><li><code>reload_model()</code> — 热重载</li><li><code>forward(input_path)</code> — 推理</li></ul><p><code>FunASRModel</code> 和 <code>WhisperModel</code>（定义在 <code>api/model.py</code>）实现此接口。</p><h3 id="句子后处理" tabindex="-1">句子后处理 <a class="header-anchor" href="#句子后处理" aria-label="Permalink to &quot;句子后处理&quot;">​</a></h3><p>ASR 输出的原始句子需要经过后处理才能用于字幕显示：</p><ol><li><strong>Cutter</strong> — 根据 <code>cut_line</code>（停顿阈值）将长句拆成短句</li><li><strong>Combiner</strong> — 根据 <code>combine_line</code> 将间隔过短的句子合并</li></ol><p>两者互为反向操作，建议只启用其中一个。如果同时启用，需要 <code>combine_line &gt; cut_line</code>。</p><h3 id="数据结构" tabindex="-1">数据结构 <a class="header-anchor" href="#数据结构" aria-label="Permalink to &quot;数据结构&quot;">​</a></h3><p>ASR 结果统一为 <code>Sentence</code> 结构（定义在 <code>_typing.py</code>），包含：</p><ul><li>文本内容</li><li>词级时间戳（<code>Word</code> 列表）</li><li>起止时间</li></ul><p>FunASR 和 Whisper 各自的 converter 负责将原始格式转为统一的 <code>Sentence</code>。</p><h2 id="与其他模块的关系" tabindex="-1">与其他模块的关系 <a class="header-anchor" href="#与其他模块的关系" aria-label="Permalink to &quot;与其他模块的关系&quot;">​</a></h2><ul><li><strong>api/core_logic.py</strong> 调用 ASR 模型进行推理</li><li><strong>api/routes/asr.py</strong> 暴露 HTTP 接口</li><li><strong>api/clients/asr_client.py</strong> 提供客户端封装</li></ul>`,19)])])}const _=a(l,[["render",i]]);export{u as __pageData,_ as default};
